    }

    .steps thead {
        display: none;
    }

    .steps > tbody > tr > td,
    .steps > tbody > tr > th {
        border-style: none !important;
    }

    .step--command,
    .step--purpose {
        display: table-row;
    }
}

figure img.scale {
    cursor: zoom-in;
    max-width: 100%;
}

figure img.scale.expanded {
    max-width: 98% !important;
    max-height: 98% !important;
    z-index: 1001;
    position: absolute;
    margin: auto auto;
    left: 0;
    right: 0;
    top: 0;
    bottom: 0;
    cursor: zoom-out;
}

#scale-background {
    z-index: 1000;
    position: absolute;
    top: 0px;
    left: 0px;
    height: 100%;
    width: 100%;
