    padding-top: 0px;
}

nav[role=toc] li.collapsed > .controller {
    opacity: 0.5;
    cursor: pointer;
    width: 0.7em;
    margin-left: -1em;
    float: left;
    line-height: 0.7em;
    background-image: url("../template_images/arrow-right.svg");
    background-size: 0.7em 0.7em;
    background-repeat: no-repeat;
    display: inline;
    height: 1.5em;
    background-position: 100% 50%;
    padding-top: 0px;
}

nav[role=toc] li.collapsed > ul {
