}

nav[role=toc] .icon:hover svg .st0,
nav[role=toc] .icon:hover svg .st1 {
    stroke: #38669e;
}

nav[role=toc] {
    background-color: white;
    box-shadow: 1px 0px 4px 0px rgba(0, 0, 0, 0.1);
